# https://github.com/jreusser/RosalindSolutions

from library import DNASequence
class ReverseComplement:
    def __init__(self, instring: str):
        self.instring = DNASequence(instring)

    def invoke(self) -> str:
        return str(self.instring.reverse_complement())

if __name__ == "__main__":
    instring = ""
    result = ReverseComplement(instring)
    print(result.invoke())